import React, { createContext, useContext, useState, useEffect, useRef } from 'react';
import { miniApp, useSignal, emitEvent, retrieveLaunchParams } from '@telegram-apps/sdk-react';

// Define theme types
export type ThemeMode = 'light' | 'dark';

/**
 * Theme params as sent by Telegram (theme_changed event).
 * Values are hex colors as required by the SDK.
 * @see https://docs.telegram-mini-apps.com/platform/theming
 */
type ThemeParams = Record<string, `#${string}`>;

const LIGHT_THEME_PARAMS: ThemeParams = {
  accent_text_color: '#2481cc',
  bg_color: '#ffffff',
  button_color: '#2481cc',
  button_text_color: '#ffffff',
  destructive_text_color: '#e53935',
  header_bg_color: '#ffffff',
  hint_color: '#999999',
  link_color: '#2481cc',
  secondary_bg_color: '#f5f5f5',
  section_bg_color: '#ffffff',
  section_header_text_color: '#2481cc',
  subtitle_text_color: '#666666',
  text_color: '#000000',
};

const DARK_THEME_PARAMS: ThemeParams = {
  accent_text_color: '#6ab2f2',
  bg_color: '#17212b',
  button_color: '#5288c1',
  button_text_color: '#ffffff',
  destructive_text_color: '#ec3942',
  header_bg_color: '#17212b',
  hint_color: '#708499',
  link_color: '#6ab3f3',
  secondary_bg_color: '#232e3c',
  section_bg_color: '#17212b',
  section_header_text_color: '#6ab3f3',
  subtitle_text_color: '#708499',
  text_color: '#f5f5f5',
};

// Define the context interface
interface ThemeContextType {
  isDark: boolean;
  toggleTheme: () => void;
  themeMode: ThemeMode;
  resetTheme: () => void;
}

// Create the context
const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

// Create a hook for using the theme context
export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};

/** Read initial theme params from launch params (Telegram sends these at startup). */
function getInitialThemeParams(): ThemeParams | null {
  try {
    const lp = retrieveLaunchParams();
    const raw = lp.tgWebAppThemeParams;
    if (!raw) return null;
    const params = typeof raw === 'string' ? (JSON.parse(raw) as Record<string, string>) : raw;
    if (!params || typeof params !== 'object') return null;
    return params as ThemeParams;
  } catch {
    return null;
  }
}

// Create the provider component
export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const isDark = useSignal(miniApp.isDark);
  const [overrideTheme, setOverrideTheme] = useState<ThemeMode | null>(null);
  const initialThemeParamsRef = useRef<ThemeParams | null>(null);

  if (initialThemeParamsRef.current === null) {
    initialThemeParamsRef.current = getInitialThemeParams();
  }

  const toggleTheme = () => {
    if (overrideTheme === null) {
      setOverrideTheme(isDark ? 'light' : 'dark');
    } else {
      setOverrideTheme(overrideTheme === 'light' ? 'dark' : 'light');
    }
  };

  const resetTheme = () => {
    setOverrideTheme(null);
  };

  const effectiveTheme: ThemeMode = overrideTheme !== null ? overrideTheme : (isDark ? 'dark' : 'light');

  // Use SDK mechanism: emit theme_changed so bindThemeParamsCssVars() updates CSS variables.
  // @see https://docs.telegram-mini-apps.com/platform/theming
  // @see https://docs.telegram-mini-apps.com/platform/events#theme-changed
  useEffect(() => {
    document.documentElement.setAttribute('data-theme', effectiveTheme);

    if (overrideTheme !== null) {
      const themeParams = effectiveTheme === 'dark' ? DARK_THEME_PARAMS : LIGHT_THEME_PARAMS;
      emitEvent('theme_changed', { theme_params: themeParams });
    } else {
      const initial = initialThemeParamsRef.current;
      if (initial) {
        emitEvent('theme_changed', { theme_params: initial });
      }
    }
  }, [effectiveTheme, overrideTheme]);
  
  return (
    <ThemeContext.Provider
      value={{
        isDark: effectiveTheme === 'dark',
        toggleTheme,
        themeMode: effectiveTheme,
        resetTheme
      }}
    >
      {children}
    </ThemeContext.Provider>
  );
};
