import { memo } from 'react';
import { useNavigate } from 'react-router-dom';
import { Breadcrumbs } from '@telegram-apps/telegram-ui';

export interface BreadcrumbItem {
  label: string;
  path?: string;
}

interface BreadcrumbsNavProps {
  items: BreadcrumbItem[];
  divider?: 'dot' | 'slash' | 'chevron';
}

const BreadcrumbsNav = ({ items, divider = 'chevron' }: BreadcrumbsNavProps) => {
  const navigate = useNavigate();

  return (
    <Breadcrumbs divider={divider}>
      {items.map((item, index) => {
        const isLast = index === items.length - 1;
        const isClickable = !isLast && item.path !== undefined;
        return (
          <Breadcrumbs.Item
            key={`${item.path ?? item.label}-${index}`}
            Component={isClickable ? 'button' : 'span'}
            onClick={
              isClickable && item.path
                ? () => navigate(item.path!)
                : undefined
            }
            style={isClickable ? { cursor: 'pointer', background: 'none', border: 'none', padding: 0, font: 'inherit', color: 'var(--tgui--link_color)' } : undefined}
          >
            {item.label}
          </Breadcrumbs.Item>
        );
      })}
    </Breadcrumbs>
  );
};

export default memo(BreadcrumbsNav);
